96	func runDashboard() error {
97		if !term.IsTerminal(int(os.Stdout.Fd())) {
98			fmt.Fprintln(os.Stderr, tui.NonTTYHint)
99			return nil
100		}
101		cfg, err := loadConfig()
102		if err != nil {
103			return err
104		}
105		cfgPath, err := config.ResolveConfigPath(cfgFile)
106		if err != nil {
107			return err
108		}
109		envPath, err := config.EnvFilePath()
110		if err != nil {
111			return err
112		}
113		return tui.RunDashboard(cfg, tui.DashboardOpts{
114			ConfigPath: cfgPath,
115			EnvPath:    envPath,
116			FilterHost: filterHost,
117			FilterRepo: filterRepo,
118		})
119	}
