121	func loadConfig() (*config.Config, error) {
122		if err := config.BootstrapEnv(); err != nil {
123			return nil, err
124		}
125		path, err := config.ResolveConfigPath(cfgFile)
126		if err != nil {
127			return nil, err
128		}
129		return config.LoadFromPath(path)
130	}
