132	func newManager(cfg *config.Config, w io.Writer) (*runner.Manager, error) {
133		tok, err := config.ResolveToken(cfg)
134		if err != nil {
135			return nil, err
136		}
137		m := runner.NewManager(tok)
138		m.Out = w
139		return m, nil
140	}
