142	func initCmd() *cobra.Command {
143		var force bool
144		var quick bool
145		cmd := &cobra.Command{
146			Use:   "init",
147			Short: "Create ~/.gh-sr with template runners.yml and env file",
148			Long: `Create ~/.gh-sr directory with a template runners.yml and env file.
149	
150	Use --quick for an interactive setup that asks for a repo and host address,
151	auto-detects everything else, and writes a working config ready for gh sr up.`,
152			RunE: func(cmd *cobra.Command, args []string) error {
153				dir, err := config.SrDir()
154				if err != nil {
155					return err
156				}
157				if err := os.MkdirAll(dir, 0o700); err != nil {
158					return err
159				}
160				runnersPath := filepath.Join(dir, "runners.yml")
161	
162				envPath, err := config.EnvFilePath()
163				if err != nil {
164					return err
165				}
166				if _, err := os.Stat(envPath); os.IsNotExist(err) {
167					if err := os.WriteFile(envPath, []byte(config.EnvFileTemplate), 0o600); err != nil {
168						return err
169					}
170					fmt.Printf("Wrote %s\n", envPath)
171				}
172	
173				if quick {
174					return runQuickInit(runnersPath, force)
175				}
176	
177				if _, err := os.Stat(runnersPath); err == nil && !force {
178					fmt.Printf("Already exists (use --force to overwrite): %s\n", runnersPath)
179				} else {
180					if err := os.WriteFile(runnersPath, config.RunnersYMLTemplate, 0o600); err != nil {
181						return err
182					}
183					fmt.Printf("Wrote %s\n", runnersPath)
184				}
185				fmt.Println("\nNext: edit ~/.gh-sr/runners.yml, then run `gh sr doctor` and `gh sr status`.")
186				fmt.Println("Authentication: run `gh auth login`.")
187				fmt.Println("Tip: use `gh sr init --quick` for interactive setup.")
188				return nil
189			},
190		}
191		cmd.Flags().BoolVar(&force, "force", false, "overwrite existing ~/.gh-sr/runners.yml")
192		cmd.Flags().BoolVar(&quick, "quick", false, "interactive setup: prompts for repo and host, auto-detects everything else")
193		return cmd
194	}
