196	func runQuickInit(runnersPath string, force bool) error {
197		scanner := bufio.NewScanner(os.Stdin)
198		prompt := func(label, defaultVal string) string {
199			if defaultVal != "" {
200				fmt.Printf("%s [%s]: ", label, defaultVal)
201			} else {
202				fmt.Printf("%s: ", label)
203			}
204			if scanner.Scan() {
205				v := strings.TrimSpace(scanner.Text())
206				if v != "" {
207					return v
208				}
209			}
210			return defaultVal
211		}
212	
213		fmt.Println("=== gh sr quick setup ===")
214		fmt.Println("This will create a working config. OS, arch, and labels are auto-detected.")
215		fmt.Println()
216	
217		repo := prompt("GitHub repo (owner/repo)", "")
218		if repo == "" {
219			return fmt.Errorf("repo is required")
220		}
221		if !strings.Contains(repo, "/") {
222			return fmt.Errorf("repo must be in owner/repo format")
223		}
224	
225		addr := prompt("SSH address of runner host (user@host, or 'local' for this machine)", "local")
226	
227		hostName := "runner-host"
228		if config.IsLocalAddr(addr) {
229			hostName = "local"
230		} else {
231			parts := strings.SplitN(addr, "@", 2)
232			if len(parts) == 2 {
233				h := strings.Split(parts[1], ":")[0]
234				h = strings.ReplaceAll(h, ".", "-")
235				if h != "" {
236					hostName = h
237				}
238			}
239		}
240	
241		baseName := strings.ReplaceAll(strings.Split(repo, "/")[1], ".", "-")
242		runnerName := baseName + "-" + hostName
243	
244		countStr := prompt("Number of runner instances", "1")
245		count := 1
246		if _, err := fmt.Sscanf(countStr, "%d", &count); err != nil || count < 1 {
247			count = 1
248		}
249	
250		profileStr := prompt(`Runner profile ("agentic" for GitHub Agentic Workflows, or empty)`, "")
251		profileLine := ""
252		if profileStr == "agentic" {
253			profileLine = "    profile: agentic\n"
254		}
255	
256		seed := fmt.Sprintf(`github: {}
257	hosts:
258	  %s:
259	    addr: %s
260	runners:
261	  - name: %s
262	    repo: %s
263	    host: %s
264	    count: %d
265	%s`, hostName, addr, runnerName, repo, hostName, count, profileLine)
266	
267		if _, err := os.Stat(runnersPath); err == nil && !force {
268			fmt.Printf("\n%s already exists. Overwrite? [y/N]: ", runnersPath)
269			if scanner.Scan() {
270				if strings.ToLower(strings.TrimSpace(scanner.Text())) != "y" {
271					fmt.Println("Aborted.")
272					return nil
273				}
274			}
275		}
276	
277		if err := os.WriteFile(runnersPath, []byte(seed), 0o600); err != nil {
278			return err
279		}
280		fmt.Printf("\nWrote %s\n", runnersPath)
281	
282		// Validate the generated config loads.
283		if _, err := config.Load(runnersPath); err != nil {
284			return fmt.Errorf("generated config is invalid: %w", err)
285		}
286	
287		fmt.Println()
288		fmt.Println("Config generated! Summary:")
289		fmt.Printf("  Host:   %s (%s)\n", hostName, addr)
290		fmt.Printf("  Runner: %s -> %s (x%d)\n", runnerName, repo, count)
291		fmt.Println("  Labels: auto-generated from host os/arch")
292		if profileStr == "agentic" {
293			fmt.Println("  Profile: agentic (GitHub Agentic Workflows)")
294		}
295		fmt.Println()
296		fmt.Println("Next steps:")
297		fmt.Println("  gh sr doctor   # verify config, GitHub access, and host connectivity")
298		fmt.Println("  gh sr up       # setup + start runners (all in one)")
299		fmt.Println()
300		fmt.Println("Authentication: run `gh auth login`.")
301	
302		return nil
303	}
