335	func addRunnerCmd() *cobra.Command {
336		var (
337			repo      string
338			org       string
339			group     string
340			host      string
341			count     int
342			labels    []string
343			ephemeral bool
344			profile   string
345		)
346		cmd := &cobra.Command{
347			Use:   "runner <name>",
348			Short: "Add a runner entry (labels auto-generated if omitted)",
349			Long: `Adds a runner to runners.yml. Labels are auto-generated from host os/arch if not specified.
350	
351	Use --org instead of --repo for organization-level runners, and --group
352	to assign the runner to a runner group. Use --profile agentic for GitHub
353	Agentic Workflows (gh-aw) runners.`,
354			Args: cobra.ExactArgs(1),
355			RunE: func(cmd *cobra.Command, args []string) error {
356				cfgPath, err := config.ResolveConfigPath(cfgFile)
357				if err != nil {
358					return err
359				}
360				name := args[0]
361				if repo == "" && org == "" {
362					return fmt.Errorf("--repo or --org is required")
363				}
364				if repo != "" && org != "" {
365					return fmt.Errorf("specify --repo or --org, not both")
366				}
367				if host == "" {
368					return fmt.Errorf("--host is required")
369				}
370				if profile != "" && profile != "agentic" {
371					return fmt.Errorf("--profile must be empty or \"agentic\"")
372				}
373				opts := config.AddRunnerOpts{
374					Name:      name,
375					Repo:      repo,
376					Org:       org,
377					Group:     group,
378					Host:      host,
379					Count:     count,
380					Labels:    labels,
381					Ephemeral: ephemeral,
382					Profile:   profile,
383				}
384				if err := config.AddRunnerFull(cfgPath, opts); err != nil {
385					return err
386				}
387				target := repo
388				if org != "" {
389					target = "org:" + org
390				}
391				fmt.Printf("Added runner %q (%s, host=%s) to %s\n", name, target, host, cfgPath)
392				return nil
393			},
394		}
395		cmd.Flags().StringVar(&repo, "repo", "", "GitHub owner/repo (required unless --org is set)")
396		cmd.Flags().StringVar(&org, "org", "", "GitHub organization (for org-level runners)")
397		cmd.Flags().StringVar(&group, "group", "", "runner group name (org-level runners only)")
398		cmd.Flags().StringVar(&host, "host", "", "host name from config (required)")
399		cmd.Flags().IntVar(&count, "count", 1, "number of parallel instances")
400		cmd.Flags().StringSliceVar(&labels, "labels", nil, "runner labels (auto-generated if empty)")
401		cmd.Flags().BoolVar(&ephemeral, "ephemeral", false, "register as ephemeral (one job then deregister)")
402		cmd.Flags().StringVar(&profile, "profile", "", `runner profile: "agentic" for GitHub Agentic Workflows (gh-aw)`)
403		return cmd
404	}
