421	func doctorCmd() *cobra.Command {
422		var strict bool
423		cmd := &cobra.Command{
424			Use:   "doctor",
425			Short: "Check config, GitHub API access, and host prerequisites",
426			Long:  "Validates local paths, configuration, GitHub API access, and SSH targets (Docker or native tooling per runner mode). See README \"Host setup\" for steps gh sr cannot automate.",
427			RunE: func(cmd *cobra.Command, args []string) error {
428				if err := config.BootstrapEnv(); err != nil {
429					return err
430				}
431				cfgPath, err := config.ResolveConfigPath(cfgFile)
432				if err != nil {
433					return err
434				}
435				envPath, err := config.EnvFilePath()
436				if err != nil {
437					return err
438				}
439	
440				cfg, cfgErr := config.LoadFromPath(cfgPath)
441				var gh *runner.GitHubClient
442				hasGitHubToken := false
443				if cfg != nil {
444					tok, tokErr := config.ResolveToken(cfg)
445					if tokErr == nil {
446						gh = runner.NewGitHubClient(tok)
447						hasGitHubToken = true
448					}
449				}
450	
451				res := doctor.Run(cmd.OutOrStdout(), cfgPath, envPath, cfg, cfgErr, gh, hasGitHubToken, filterHost, filterRepo, strict)
452				if code := doctor.ExitCode(res, strict); code != 0 {
453					os.Exit(code)
454				}
455				return nil
456			},
457		}
458		cmd.Flags().BoolVar(&strict, "strict", false, "non-zero exit if any check is WARN (default: only FAIL fails the run)")
459		return cmd
460	}
