153		fmt.Fprintln(w, "\nUpdate complete.")
154		return nil
155	}
156	
157	// CollectStatus gathers runner status rows like gh sr status.
158	//
159	// Runners are grouped by host so that each host requires only one SSH connection.
160	// All host groups are queried concurrently, reducing wall-clock time from
161	// O(N_hosts × SSH_latency) to O(SSH_latency) for multi-host configurations.
162	func CollectStatus(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) ([]runner.RunnerStatus, error) {
163		if err := ResolveHostInfo(w, cfg); err != nil {
164			return nil, err
165		}
166		runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
167	
168		// Group runners by host, preserving original order for deterministic output.
169		type hostGroup struct {
170			name    string
171			runners []config.RunnerConfig
172		}
173		var groups []hostGroup
174		groupIdx := make(map[string]int)
175		for _, rc := range runners {
176			if i, ok := groupIdx[rc.Host]; ok {
177				groups[i].runners = append(groups[i].runners, rc)
178			} else {
179				groupIdx[rc.Host] = len(groups)
180				groups = append(groups, hostGroup{name: rc.Host, runners: []config.RunnerConfig{rc}})
181			}
182		}
183	
184		type groupResult struct {
185			statuses []runner.RunnerStatus
186			err      error
187		}
188		results := make([]groupResult, len(groups))
189	
190		var wg sync.WaitGroup
191		var wMu sync.Mutex // guards writes to w
192	
193		for i, g := range groups {
194			wg.Add(1)
195			go func(i int, g hostGroup) {
196				defer wg.Done()
197				hcfg := cfg.Hosts[g.name]
198				h, err := ConnectHost(g.name, hcfg)
199				if err != nil {
200					if w != nil {
201						wMu.Lock()
202						fmt.Fprintf(w, "Warning: cannot connect to %s: %v\n", g.name, err)
203						wMu.Unlock()
204					}
205					var unreachable []runner.RunnerStatus
206					for _, rc := range g.runners {
207						for _, name := range rc.InstanceNames() {
208							repoDisplay := rc.Repo
209							if rc.Org != "" {
210								repoDisplay = "org:" + rc.Org
211							}
212							unreachable = append(unreachable, runner.RunnerStatus{
213								Instance: name,
214								Host:     rc.Host,
215								Repo:     repoDisplay,
216								Mode:     "native",
217								Local:    "unreachable",
218							})
219						}
220					}
221					results[i] = groupResult{statuses: unreachable}
222					return
223				}
224				defer h.Close()
225	
226				var statuses []runner.RunnerStatus
227				for _, rc := range g.runners {
228					s, err := mgr.Status(h, rc)
229					if err != nil {
230						results[i] = groupResult{err: err}
231						return
232					}
233					statuses = append(statuses, s...)
234				}
235				results[i] = groupResult{statuses: statuses}
236			}(i, g)
237		}
238		wg.Wait()
239	
240		var allStatuses []runner.RunnerStatus
241		for _, r := range results {
242			if r.err != nil {
243				return nil, r.err
244			}
245			allStatuses = append(allStatuses, r.statuses...)
246		}
247	
248		mgr.EnrichWithGitHubStatus(allStatuses, cfg)
249		return allStatuses, nil
250	}
251	
252	// Logs returns recent log lines for a runner instance or base name.
253	func Logs(cfg *config.Config, mgr *runner.Manager, filterHost, target string) (string, error) {
254		if err := ResolveHostInfo(nil, cfg); err != nil {
255			return "", err
256		}
257		rc, err := cfg.FindRunnerForLogs(target, filterHost)
258		if err != nil {
259			return "", err
260		}
261		instance, err := rc.ResolveRunnerInstance(target)
262		if err != nil {
263			return "", err
264		}
265		hcfg := cfg.Hosts[rc.Host]
266		h, err := ConnectHost(rc.Host, hcfg)
267		if err != nil {
268			return "", err
269		}
270		defer h.Close()
271		return mgr.Logs(h, *rc, instance)
272	}
273	
274	// CleanupOffline removes offline runners via the GitHub API.
275	func CleanupOffline(w io.Writer, cfg *config.Config, mgr *runner.Manager) (int, error) {
276		fmt.Fprintln(w, "Cleaning up offline runners...")
277		removed, err := mgr.CleanupOffline(cfg)
278		if err != nil {
279			return 0, err
280		}
281		if removed == 0 {
282			fmt.Fprintln(w, "No offline runners found.")
283		} else {
284			fmt.Fprintf(w, "Removed %d offline runner(s).\n", removed)
285		}
286		return removed, nil
287	}
