89	// nativeConfigURL returns the --url value for config.sh / config.cmd.
90	func nativeConfigURL(rc config.RunnerConfig) string {
91		if rc.Org != "" {
92			return "https://github.com/" + rc.Org
93		}
94		return "https://github.com/" + rc.Repo
95	}
96	
97	func windowsNativeConfigScript(h *host.Host, rc config.RunnerConfig, instanceName, regToken string) string {
98		labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
99		cmd := fmt.Sprintf(
100			"& .\\config.cmd --unattended --url %s --token %s --name %s --labels %s --work '_work' --replace",
101			powerShellSingleQuoted(nativeConfigURL(rc)),
102			powerShellSingleQuoted(regToken),
103			powerShellSingleQuoted(instanceName),
104			powerShellSingleQuoted(labels),
105		)
106		if rc.Group != "" {
107			cmd += fmt.Sprintf(" --runnergroup %s", powerShellSingleQuoted(rc.Group))
108		}
109		if rc.Ephemeral {
110			cmd += " --ephemeral"
111		}
112		return strings.Join([]string{
113			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
114			"Set-Location -Path $runnerDir",
115			cmd,
116		}, "; ")
117	}
118	
119	// staleRegistrationMsg is the substring the Actions runner writes to its log when the
120	// server-side registration has been deleted (auto-pruned after inactivity).
121	const staleRegistrationMsg = "runner registration has been deleted from the server"
122	
123	func windowsNativeStartScript(h *host.Host, instanceName string) string {
124		// Win32-OpenSSH tears down the session job on disconnect, killing Start-Process children.
125		// Win32_Process.Create starts outside that job so the listener survives after gh sr closes SSH.
126		parts := []string{
127			windowsRunnerDirAssignment(h, "runnerDir", instanceName) + "; ",
128			`$pidFile = Join-Path $runnerDir '.runner_pid'; `,
129			`$logFile = Join-Path $runnerDir 'runner.log'; `,
130			`if (Test-Path $pidFile) { $existingPid = Get-Content $pidFile; try { Get-Process -Id $existingPid -EA Stop | Out-Null; Write-Host 'already running'; exit 0 } catch {} }; `,
131			`$cmdArg = 'cd /d "' + $runnerDir + '" && run.cmd > "' + $logFile + '" 2>&1'; `,
132			`$fullLine = 'cmd.exe /c ' + $cmdArg; `,
133			`$cim = Invoke-CimMethod -ClassName Win32_Process -MethodName Create -Arguments @{ CommandLine = $fullLine; CurrentDirectory = $runnerDir }; `,
134			`if ($cim.ReturnValue -ne 0) { Write-Host ('Win32_Process.Create failed: ' + $cim.ReturnValue); exit 1 }; `,
135			`$cim.ProcessId | Out-File -FilePath $pidFile -NoNewline; `,
136			`Write-Host ('started PID ' + $cim.ProcessId)`,
137		}
138		return strings.Join(parts, "")
139	}
140	
141	// windowsCheckStaleRegistration returns a PowerShell snippet that waits briefly for the
142	// runner process to either stay alive (healthy) or exit, then checks runner.log for the
143	// stale-registration message. It writes "stale" to stdout if detected, "ok" otherwise.
144	func windowsCheckStaleRegistration(h *host.Host, instanceName string) string {
145		return fmt.Sprintf(
146			"%s; $pidFile = Join-Path $runnerDir '.runner_pid'; "+
147				"$logFile = Join-Path $runnerDir 'runner.log'; "+
148				"Start-Sleep -Seconds 5; "+
149				"$pid = Get-Content $pidFile -EA SilentlyContinue; "+
150				"$alive = $false; if ($pid) { try { Get-Process -Id $pid -EA Stop | Out-Null; $alive = $true } catch {} }; "+
151				"if ($alive) { Write-Host 'ok' } "+
152				"elseif ((Test-Path $logFile) -and (Select-String -Path $logFile -Pattern %s -Quiet)) { Write-Host 'stale' } "+
153				"else { Write-Host 'ok' }",
154			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
155			powerShellSingleQuoted(staleRegistrationMsg),
156		)
157	}
158	
159	// windowsDeleteRunnerConfig removes the .runner file so setupNative will re-configure.
160	func windowsDeleteRunnerConfig(h *host.Host, instanceName string) string {
161		return fmt.Sprintf(
162			"%s; Remove-Item -Force (Join-Path $runnerDir '.runner') -EA SilentlyContinue; "+
163				"Remove-Item -Force (Join-Path $runnerDir '.credentials') -EA SilentlyContinue; "+
164				"Remove-Item -Force (Join-Path $runnerDir '.credentials_rsaparams') -EA SilentlyContinue",
165			windowsRunnerDirAssignment(h, "runnerDir", instanceName),
166		)
167	}
